    ('cat_high_contrast_cards', 5, 5, 'visible', true, true, 'Multi-stage visual development', 'hahaland Baby Flash Cards Visual Stimulation Cards 0-3-6-12-36 Months', 'hahaland', 'hahaland', 'https://hahaland.com/products/baby-flash-cards-baby-visual-stimulation-cards-0-3-6-12-36-months', NULL, 'GBP 12.99', 'in_stock', NULL, 'A set of baby flash cards offering four stages of visual stimulation, starting with high-contrast black and white for newborns and progressing to colors for older infants. Made from thick card with an anti-glare surface.', 'The hahaland cards provide a clear progression through different visual stages, making them a long-term investment for parents. The inclusion of specific 0-3 month high-contrast cards, along with features like thick card and anti-glare surface, makes them a suitable and practical choice for this category.', 'The hahaland cards provide a clear progression through different visual stages, making them a long-term investment for parents. The inclusion of specific 0-3 month high-contrast cards, along with features like thick card and anti-glare surface, makes them a suitable and practical choice for this category.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 1, 1, 'visible', true, false, 'Early grasping and sensory exploration', 'Oball Classic™ Easy-Grasp Toy', 'Bright Starts', 'Boots', 'https://www.boots.com/baby-einstein-oball-classic-easy-grasp-toy-10307276', NULL, 'GBP 3.99', 'in_stock', NULL, 'A flexible, lightweight ball with 32 finger holes, perfect for tiny hands to grip, roll, and throw. Its soft construction and easy-care material make it ideal for early playtime.', 'Excellent design for early grasping with numerous finger holes, promoting fine motor skills and sensory development. High rating and review count indicate strong retail proof.', 'Excellent design for early grasping with numerous finger holes, promoting fine motor skills and sensory development. High rating and review count indicate strong retail proof.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 2, 2, 'visible', true, true, 'Teething and grasping development', 'Winkel Rattle & Sensory Teether Toy', 'Manhattan Toy', 'Jojo Maman Bébé', 'https://www.manhattantoy.com/products/winkel', NULL, 'GBP 14.00', 'in_stock', NULL, 'An award-winning teether and rattle with a mesmerizing maze of soft, continuous, BPA-free loops that are easy for tiny hands to grasp, hold, and chew. Can be refrigerated for added soothing.', 'Unique design with bendable loops makes it exceptionally easy for infants to grasp and manipulate, supporting fine motor skills and providing teething relief.', 'Unique design with bendable loops makes it exceptionally easy for infants to grasp and manipulate, supporting fine motor skills and providing teething relief.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 3, 3, 'visible', true, true, 'Sensory stimulation and fine motor skills', 'Freddie the Firefly Activity Toy', 'Lamaze', 'John Lewis', 'https://www.johnlewis.com/lamaze-freddie-the-firefly-activity-toy/p109915929', NULL, 'GBP 14.99', 'in_stock', NULL, 'A friendly firefly with a soft velour body, bright colors, patterns, and textures. Features a peek-a-boo mirror, squeaker, clinking rings, and a tethered ladybug teether. Easily clips to strollers and carriers.', 'Multi-sensory features (crinkle, squeaker, teether, mirror, varied textures) engage multiple senses and encourage reaching, grasping, and tactile exploration. Clip-on design adds versatility.', 'Multi-sensory features (crinkle, squeaker, teether, mirror, varied textures) engage multiple senses and encourage reaching, grasping, and tactile exploration. Clip-on design adds versatility.', NULL, NULL, true, 'Good gift', NULL, 'Remove all packaging and tags before giving to a child', NULL, ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 4, 4, 'visible', true, true, 'Comprehensive sensory and motor development', 'Hello Baby Newborn Kit', 'Taf Toys', 'John Lewis', 'https://www.johnlewis.com/taf-toys-hello-baby-newborn-kit/p111759988', NULL, 'GBP 32.99', 'in_stock', NULL, 'A 12-piece kit designed to meet newborns'' developmental needs, encouraging sensory exploration and tummy time. Includes flash cards, a baby-safe mirror, tummy time pillow, rattle ring, crinkling lion cub, and a soft lion blankie.', 'Offers a comprehensive set of developmental toys for newborns, covering visual, auditory, and tactile stimulation, as well as supporting tummy time and early grasping.', 'Offers a comprehensive set of developmental toys for newborns, covering visual, auditory, and tactile stimulation, as well as supporting tummy time and early grasping.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 5, 5, 'visible', true, true, 'Tactile exploration and motor skill development', 'Grasping Ball - Newborn Naturals', 'Little Dutch', 'Scandiborn', 'https://www.scandiborn.co.uk/products/little-dutch-grasping-ball-newborn-naturals', NULL, 'GBP 12.71', 'in_stock', NULL, 'A beautifully soft grasping ball with varied textures and subtle colors, designed to support sensory exploration and motor skills from birth. Easy for little hands to grab, roll, and explore.', 'Soft fabric and varied textures provide gentle tactile stimulation, while its design encourages grasping, rolling, and motor skill development.', 'Soft fabric and varied textures provide gentle tactile stimulation, while its design encourages grasping, rolling, and motor skill development.', NULL, NULL, true, 'Good gift', NULL, NULL, NULL, ARRAY[]::text[], 'none'),
    ('cat_rear_facing_car_seat', 1, 1, 'visible', true, false, 'Overall safety, comfort, and ease of use with lie-flat and SlideTech features.', 'Pebble 360 Pro2', 'Maxi-Cosi', 'John Lewis', 'https://www.johnlewis.com/maxi-cosi-pebble-360-pro2-car-seat/twillic-black/p112093409', NULL, 'GBP 207.99', 'in_stock', NULL, 'A premium i-Size infant car seat offering a full lie-flat position for maximum sleep comfort, 360-degree rotation, and SlideTech for easy access. Suitable from birth to approximately 15 months.', 'This seat excels in safety (Good ADAC rating), comfort (lie-flat), and user-friendliness (SlideTech, 360 rotation), directly addressing the need for safe and prepared early outings.', 'This seat excels in safety (Good ADAC rating), comfort (lie-flat), and user-friendliness (SlideTech, 360 rotation), directly addressing the need for safe and prepared early outings.', NULL, NULL, false, 'Parent buy', NULL, 'ISOFIX base sold separately; Always check car seat compatibility with your vehicle before purchase.', NULL, ARRAY[]::text[], 'none'),
    ('cat_rear_facing_car_seat', 2, 2, 'visible', true, true, 'Ergonomic lie-flat position and superior side-impact protection.', 'Cloud T i-Size Rotating Baby Car Seat', 'Cybex', 'John Lewis', 'https://www.johnlewis.com/cybex-cloud-t-i-size-rotating-baby-car-seat/p110535706', NULL, 'GBP 199.95', 'in_stock', NULL, 'An i-Size infant car seat with an innovative lie-flat recline for use in and out of the car, 180-degree rotation (with Base T), and enhanced side-impact protection. Suitable from birth to approximately 24 months.', 'Its lie-flat technology and ADAC Test Winner status provide excellent comfort and safety for newborns, making early journeys more comfortable and secure.', 'Its lie-flat technology and ADAC Test Winner status provide excellent comfort and safety for newborns, making early journeys more comfortable and secure.', NULL, NULL, false, 'Parent buy', NULL, 'ISOFIX Base T sold separately; Always check car seat compatibility with your vehicle before purchase.', NULL, ARRAY[]::text[], 'none'),
    ('cat_rear_facing_car_seat', 3, 3, 'visible', true, true, 'Ultra-lightweight and baseless ISOFIX installation for easy transfers.', 'PIPA URBN R129 Baby Car Seat', 'Nuna', 'John Lewis', 'https://www.johnlewis.com/nuna-pipa-urbn-r129-baby-car-seat-caviar/p110165707', NULL, 'GBP 300.00', 'in_stock', NULL, 'An ultra-lightweight infant car seat (3.3kg) with integrated baseless ISOFIX installation, allowing for quick and secure fitting without a separate base. Ideal for urban parents and frequent car changes.', 'Its unique baseless ISOFIX and ultra-lightweight design make it exceptionally convenient for parents needing to frequently move the car seat between vehicles or use ride-shares, simplifying early outings.', 'Its unique baseless ISOFIX and ultra-lightweight design make it exceptionally convenient for parents needing to frequently move the car seat between vehicles or use ride-shares, simplifying early outings.', NULL, NULL, false, 'Parent buy', NULL, 'Always check car seat compatibility with your vehicle before purchase.', NULL, ARRAY[]::text[], 'none'),
    ('cat_rear_facing_car_seat', 4, 4, 'visible', true, true, 'Extreme lightness, ergonomic design, and suitability for premature babies.', 'Pixel PRO 2.0 C Infant Carrier', 'Avionaut', 'Pramworld', 'https://www.pramworld.co.uk/avionaut-pixel-pro-2-0-c-infant-carrier-black/', NULL, 'GBP 209.00', 'in_stock', NULL, 'The lightest i-Size infant car seat on the market (2.5kg) featuring a modular insert with Cloud Care System for ergonomic positioning and superior safety, even for premature babies.', 'Its ultra-lightweight design and ergonomic insert specifically cater to the delicate needs of newborns and premature babies, ensuring optimal comfort and safety during early travels.', 'Its ultra-lightweight design and ergonomic insert specifically cater to the delicate needs of newborns and premature babies, ensuring optimal comfort and safety during early travels.', NULL, NULL, false, 'Parent buy', NULL, 'ISOFIX base sold separately; Always check car seat compatibility with your vehicle before purchase.', NULL, ARRAY[]::text[], 'none'),
    ('cat_rear_facing_car_seat', 5, 5, 'visible', true, true, 'Budget-friendly extended rear-facing with 360-degree rotation.', 'Turn2Me DLX i-Size R129 360° Rotating Car Seat', 'Graco', 'Amazon UK', 'https://www.amazon.co.uk/Graco-Rotating-Rearward-40-105cm-76-105cm/dp/B0D2LMQR5F', NULL, 'GBP 125.99', 'in_stock', NULL, 'An affordable i-Size car seat offering 360-degree rotation and extended rear-facing capability from birth up to approximately 4 years. Features easy installation and multiple recline positions.', 'Provides excellent value as a budget-friendly option that doesn''t compromise on key features like 360-degree rotation and extended rear-facing, making it accessible for more families.', 'Provides excellent value as a budget-friendly option that doesn''t compromise on key features like 360-degree rotation and extended rear-facing, making it accessible for more families.', NULL, NULL, false, 'Parent buy', NULL, 'Side-impact protection pod needs to be fitted separately each time; Always check car seat compatibility with your vehicle before purchase.', NULL, ARRAY[]::text[], 'none'),
    ('cat_soft_carrier_sling', 1, 1, 'visible', true, false, 'newborns and early months', 'Embrace Baby Carrier', 'Ergobaby', 'Mamas & Papas', 'https://www.mamasandpapas.com/products/ergobaby-embrace-carrier-black-617825300', NULL, 'GBP 88.00', 'in_stock', NULL, 'A soft, simple, and easy-to-use newborn-ready carrier designed for baby''s first 12 months, providing ergonomic support and a close, comforting hold.', 'Consistently recommended for newborns due to its soft fabric, ease of use (3 clicks, no tying), and ergonomic design that supports healthy hip development. Ideal for the 1-3 month age band to promote bonding and provide hands-free comfort.', 'Consistently recommended for newborns due to its soft fabric, ease of use (3 clicks, no tying), and ergonomic design that supports healthy hip development. Ideal for the 1-3 month age band to promote bonding and provide hands-free comfort.', NULL, NULL, false, 'Parent buy', NULL, 'Always follow recognised safe babywearing guidance and fit checks (TICKS guidelines).', NULL, ARRAY[]::text[], 'none'),
    ('cat_soft_carrier_sling', 2, 2, 'visible', true, true, 'back support and longer wearing sessions', 'Baby Carrier Harmony', 'BabyBjörn', 'John Lewis', 'https://www.johnlewis.com/babybjorn-harmony-baby-carrier/p5612075', NULL, 'GBP 167.12', 'in_stock', NULL, 'A soft, flexible, and ergonomic baby carrier with a luxurious feel, featuring a waist belt, padded back support, and padded shoulder straps for ultimate comfort.', 'Highly rated for its excellent back support and comfort, making it suitable for parents who wear their baby for extended periods. It''s designed for hip health and grows with the baby from newborn to 3 years.', 'Highly rated for its excellent back support and comfort, making it suitable for parents who wear their baby for extended periods. It''s designed for hip health and grows with the baby from newborn to 3 years.', NULL, NULL, false, 'Parent buy', NULL, 'Always follow recognised safe babywearing guidance and fit checks.', NULL, ARRAY[]::text[], 'none'),
    ('cat_soft_carrier_sling', 3, 3, 'visible', true, true, 'budget-friendly, close contact, and early newborn stage', 'Essential Baby Wrap - Mid Grey', 'Izmi', 'Argos', 'https://www.argos.co.uk/product/9566569', NULL, 'GBP 35.00', 'in_stock', NULL, 'A soft and stretchy cotton-blend wrap designed for newborns and infants, providing a comforting hold and even weight distribution across the wearer''s back and shoulders.', 'An excellent budget-friendly option for parents seeking the close, comforting contact of a wrap. Suitable from birth (2.3kg) and machine washable. While it requires some practice to tie, it''s highly rated for comfort and effectiveness in settling newborns.', 'An excellent budget-friendly option for parents seeking the close, comforting contact of a wrap. Suitable from birth (2.3kg) and machine washable. While it requires some practice to tie, it''s highly rated for comfort and effectiveness in settling newborns.', NULL, NULL, false, 'Parent buy', NULL, 'Always follow recognised safe babywearing guidance and fit checks (TICKS guidelines).; Fit indoors to prevent fabric from touching the floor.', NULL, ARRAY[]::text[], 'none'),
    ('cat_soft_carrier_sling', 4, 4, 'visible', true, true, 'versatility and all-season comfort', 'Omni 360 Cool Air Mesh Baby Carrier', 'Ergobaby', 'John Lewis', 'https://www.johnlewis.com/ergobaby-omni-360-mesh-baby-carrier/p3501816', NULL, 'GBP 164.90', 'in_stock', NULL, 'A four-position, newborn-ready carrier designed for baby''s first 48 months, offering patented ergonomic support and a breathable mesh fabric for comfort in all seasons.', 'This carrier is highly versatile, suitable from birth without an infant insert, and offers four carrying positions. The Cool Air Mesh makes it ideal for the UK''s varying climate, and its ergonomic design supports healthy hip development. It''s a great all-rounder for parents seeking a long-term solution.', 'This carrier is highly versatile, suitable from birth without an infant insert, and offers four carrying positions. The Cool Air Mesh makes it ideal for the UK''s varying climate, and its ergonomic design supports healthy hip development. It''s a great all-rounder for parents seeking a long-term solution.', NULL, NULL, false, 'Parent buy', NULL, 'Always follow recognised safe babywearing guidance and fit checks (TICKS guidelines).', NULL, ARRAY[]::text[], 'none'),
    ('cat_soft_carrier_sling', 5, 5, 'visible', true, true, 'micro-adjustability and longevity from newborn to toddler', 'X Baby Carrier', 'Boba', 'Boba Baby UK', 'https://bobababy.co.uk/collections/boba-x-baby-carrier', NULL, 'GBP 99.99', 'in_stock', NULL, 'An all-in-one adjustable baby carrier that offers comfort and support for newborns and toddlers, featuring micro-adjustments for a perfect fit as your baby grows.', 'The Boba X is highly praised for its exceptional adjustability, making it suitable from birth (7lbs) through to toddlerhood (45lbs) without the need for an infant insert. Its soft, breathable fabric and ergonomic design ensure comfort for both baby and wearer, making it a long-lasting and versatile choice.', 'The Boba X is highly praised for its exceptional adjustability, making it suitable from birth (7lbs) through to toddlerhood (45lbs) without the need for an infant insert. Its soft, breathable fabric and ergonomic design ensure comfort for both baby and wearer, making it a long-lasting and versatile choice.', NULL, NULL, false, 'Parent buy', NULL, 'Always follow recognised safe babywearing guidance and fit checks.', NULL, ARRAY[]::text[], 'none'),
    ('cat_washable_floor_play_mat', 1, 1, 'visible', true, false, 'stylish and durable investment', 'The Mariner Playmat', 'Totter + Tumble', 'Totter + Tumble UK', 'https://totterandtumble.co.uk/products/the-mariner-playmat', NULL, 'GBP 160.00', 'in_stock', NULL, 'A high-density, cushioned, and reversible playmat that is easy to wipe clean and designed to complement modern interiors.', 'Offers excellent cushioning and a wipe-clean surface, crucial for early movements and easy maintenance. The reversible design provides versatility and aesthetic appeal, making it a long-term investment.', 'Offers excellent cushioning and a wipe-clean surface, crucial for early movements and easy maintenance. The reversible design provides versatility and aesthetic appeal, making it a long-term investment.', NULL, NULL, true, 'Good gift', NULL, 'Use only during awake, supervised play.', NULL, ARRAY[]::text[], 'none'),
    ('cat_washable_floor_play_mat', 2, 2, 'visible', true, true, 'best overall budget-friendly option', 'Nuby Foldable Playmat Road Map', 'Nuby', 'Amazon UK', 'https://www.amazon.co.uk/Nuby-Foldable-Playmat-Road-Map/dp/B0FLPZG8JG', NULL, 'GBP 39.99', 'in_stock', NULL, 'A lightweight, reversible XPE foam playmat with an engaging road map design, perfect for tummy time and easy storage.', 'Highly practical and affordable, offering a safe and stimulating surface for early play. Its foldable nature makes it convenient for small spaces and travel.', 'Highly practical and affordable, offering a safe and stimulating surface for early play. Its foldable nature makes it convenient for small spaces and travel.', NULL, NULL, true, 'Good gift', NULL, 'Use only during awake, supervised play.', NULL, ARRAY[]::text[], 'none'),
    ('cat_washable_floor_play_mat', 3, 3, 'visible', true, true, 'sensory development', 'Etta Loves Plant Print Reversible Playmat', 'Etta Loves', 'John Lewis', 'https://www.johnlewis.com/etta-loves-plant-print-reversible-sensory-playmat/p110367711', NULL, 'GBP 66.00', 'in_stock', NULL, 'An organic cotton playmat with scientifically inspired patterns designed to support babies'' visual and cognitive development, reversible for different age stages.', 'Its focus on sensory development with high-contrast patterns is ideal for newborns. The organic, machine-washable material ensures comfort and hygiene.', 'Its focus on sensory development with high-contrast patterns is ideal for newborns. The organic, machine-washable material ensures comfort and hygiene.', NULL, NULL, true, 'Good gift', NULL, 'Use only during awake, supervised play.', NULL, ARRAY[]::text[], 'none'),
    ('cat_washable_floor_play_mat', 4, 4, 'visible', true, true, 'thick cushioning and minimalist design', 'Gus + Beau Rainbow Playmat', 'Gus + Beau', 'Gus + Beau', 'https://www.gusandbeau.com/products/rainbow-playmat-set-in-cream', NULL, 'GBP 75.00', 'in_stock', NULL, 'A thick, non-toxic EVA foam puzzle playmat with a minimalist rainbow design, providing excellent cushioning for hard floors.', 'Offers superior cushioning for safety and comfort during active play, while its minimalist design blends well with modern home decor.', 'Offers superior cushioning for safety and comfort during active play, while its minimalist design blends well with modern home decor.', NULL, NULL, true, 'Good gift', NULL, 'Use only during awake, supervised play.', NULL, ARRAY[]::text[], 'none'),
    ('cat_washable_floor_play_mat', 5, 5, 'visible', true, true, 'portability and large play area', 'Skip Hop Roll-up Playmat', 'Skip Hop', 'John Lewis', 'https://www.google.com/search?tbm=shop&q=Skip+Hop+Roll-up+Playmat+UK', NULL, 'GBP 81.51', 'in_stock', NULL, 'A large, reversible, wipe-clean playmat that easily rolls up for storage and portability, offering ample space for baby''s movements.', 'Its large size provides plenty of room for babies to explore and move, while its roll-up design makes it highly convenient for storage and travel.', 'Its large size provides plenty of room for babies to explore and move, while its roll-up design makes it highly convenient for storage and travel.', NULL, NULL, true, 'Good gift', NULL, 'Use only during awake, supervised play.', NULL, ARRAY[]::text[], 'google_shopping')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
)
INSERT INTO public.pl_stage3_picks (
  age_band_id,
  category_type_id,
  source_category_entity_id,
  pick_rank,
  longlist_rank,
  status,
  is_visible,
  is_locked,
  best_for_tag,
  product_name,
  brand,
  retailer,
  product_url,
  image_url,
  price_text,
  stock_status,
  age_mark_on_listing,
  product_description,
  ember_verdict,
  why_it_fits,
  caveats,
  buy_borrow_hold_off,
  gift_suitable,
  gift_note,
  ownership_note,
  safety_notes,
  evidence_tier,
  evidence_sources,
  founder_qa_flag,
  research_payload
)
SELECT
  '1-3m',
  ct.id,
  r.source_category_entity_id,
  r.pick_rank,
  r.longlist_rank,
  r.status,
  r.is_visible,
  r.is_locked,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.image_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.product_description,
  r.ember_verdict,
  r.why_it_fits,
  r.caveats,
  r.buy_borrow_hold_off,
  r.gift_suitable,
  r.gift_note,
  r.ownership_note,
  r.safety_notes,
  r.evidence_tier,
  r.evidence_sources,
  r.founder_qa_flag,
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-18T09:49:09.534Z',
    'research_schema_version', 'ember_picks_research_v2',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM stage3_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '1-3m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

